external_knowledge:
- "grown beyond a certain size and roughness" refers to tumors with worst radius > 30 and worst texture > 200; 
- "demographic details" includes patient ID, age, gender, and ethnicity; 
- "study participation information" includes study title, start date, and join date; 
- "tumor characteristics" includes mean radius, texture, perimeter, area, worst radius, worst texture, worst perimeter, worst area, and fractal dimension.

sql:
SELECT patient_id, AVG(area_mean) AS average_area_mean
FROM tumor_characteristics
GROUP BY patient_id;

SELECT COUNT(*) AS malignant_count
FROM patients
WHERE diagnosis = 'M';
